#nullable enable // autogenerated  

using System.Collections.Generic;
using MVZ2.GameContent.Buffs;
using MVZ2Logic.Artifacts;
using MVZ2Logic.Definitions;
using MVZ2Logic.Entities;
using PVZEngine.Auras;
using PVZEngine.Buffs;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Artifacts
{
    [AutoArtifactDefinition(VanillaArtifactNames.PbCore)]
    public class PbCore : ArtifactDefinition
    {
        public PbCore(string nsp, string name) : base(nsp, name)
        {
            // 携带时：给全场我方器械赋予辐射保护光环。  
            // 卸下（制品移除）时，光环随之消失，只移除本光环添加的 buff 实例，  
            // 不影响器械 Init 时自带的 RadiationProtection buff。  
            AddAura(new ProtectionAura());
        }

        public override void PostUpdate(Artifact artifact)
        {
            base.PostUpdate(artifact);
            artifact.SetGlowing(true);
        }

        public class ProtectionAura : AuraEffectDefinition
        {
            // 光环添加的 buff 为 RadiationProtection。  
            public ProtectionAura() : base(VanillaBuffID.Entity.RadiationProtection)
            {
            }

            public override void GetAuraTargets(AuraEffect auraEffect, List<IBuffTarget> results)
            {
                var level = auraEffect.Source.GetLevel();
                // 全场我方器械（植物且友方）。  
                results.AddRange(level.FindEntities(e => e.Type == EntityTypes.PLANT && e.IsFriendlyEntity()));
            }

            // 设置该光环 buff 的保护等级为 0.8（减免 80%）。  
            public override void UpdateTargetBuff(AuraEffect effect, IBuffTarget target, Buff buff)
            {
                base.UpdateTargetBuff(effect, target, buff);
                buff.SetProperty(RadiationProtection.PROP_Protection_Level, PROTECTION_LEVEL);
            }
        }

        public const float PROTECTION_LEVEL = 0.8f;
    }
}
